// Minimal patch trigger and approval flow
exports.handler = async (event) => {
  const { detail } = event;

  // Validate drift event and check approval status
  const approvalRequired = await checkPatchApproval(detail.resourceType);
  const approvedPatches = await getApprovedPatches();

  if (approvalRequired && !approvedPatches.includes(detail.patchId)) {
    await triggerApprovalWorkflow(detail);
    return { status: 'approval_required' };
  }

  // Execute patch based on resource type
