## Code Example
```javascript
// gate.js
const AWS = require('aws-sdk');
const ssm = new AWS.SSM();
let cache = { enabled: true, ts: 0 };
exports.handler = async (event, context) => {
  if (Date.now() - cache.ts > 60000) {
    const p = await ssm.getParameter({ Name: '/gate/noncritical', WithDecryption: true }).promise();
    cache.enabled = p.Parameter.Value === 'enabled';
    cache.ts = Date.now();
  }
  const path = event.path || '/';
  if (!cache.enabled && path.startsWith('/noncritical')) {
    return { statusCode: 429, body: 'Throttled' };
  }
  // proceed with normal flow
  return { statusCode: 200, body: 'OK' };
};
```

