async function remediateBucketPolicy(bucket){
  const policyObj = await s3.getBucketPolicy({Bucket: bucket}).promise().catch(()=>null);
  if(!policyObj) return;
  const policy = JSON.parse(policyObj.Policy);
  policy.Statement = policy.Statement.filter(s => !(s.Effect === 'Allow' && (!s.Principal || s.Principal === '*')));
